mapper.select:
select 
from notifications
where recipient_user_id = #{recipientUserId}
  and type = #{type}
  and reference_type = #{referenceType}
  and reference_id = #{referenceId}

select count(*)
from notifications n
where n.recipient_user_id = #{recipientUserId}
  and n.read_at is null
  and n.type = #{type}
  and n.reference_type = #{referenceType}
  and exists (
      select 1
      from friendships f
      where f.id = n.reference_id
        and f.status = #{status}
  )

select 
from notifications n
where n.recipient_user_id = #{recipientUserId}
  and n.read_at is null
  and n.type = #{type}
  and n.reference_type = #{referenceType}
  and exists (
      select 1
      from friendships f
      where f.id = n.reference_id
        and f.status = #{status}
  )
order by n.created_at desc, n.id desc
limit #{limit}

mapper.update:
update notifications
set read_at = #{readAt},
    updated_at = current_timestamp
where recipient_user_id = #{recipientUserId}
  and reference_type = #{referenceType}
  and reference_id = #{referenceId}
  and read_at is null
